1	import { spawn } from "node:child_process";
2	import { once } from "node:events";
3	import { createInterface } from "node:readline";
4	import {
5		parseInitEvent,
6		type SessionEvent,
7		type SessionInit,
8		sessionEventSchema,
9	} from "./events.ts";
10	import { type SessionKind, spawnableRow } from "./kinds.ts";
11	
12	export interface SpawnSessionOptions {
13		kind: SessionKind;
14		cwd: string;
15		prompt: string;
16		// Session id to resume; omit to start a fresh session.
17		resume?: string;
18		onEvent?: (event: SessionEvent) => void;
19	}
20	
21	export interface SessionOutcome {
22		sessionId: string | undefined;
23		exitCode: number | null;
24		signal: NodeJS.Signals | null;
25		// A resume whose transcript is gone: exit 1 + the CLI's loud stderr line.
26		stale: boolean;
27		stderr: string;
28	}
29	
30	export interface SessionProcess {
31		// Resolves with `system/init`; rejects (SessionSpawnError) if the process
32		// dies first, which is how a stale resume surfaces.
33		started: Promise<SessionInit>;
34		done: Promise<SessionOutcome>;
35		kill(): void;
36	}
37	
38	export class SessionSpawnError extends Error {
39		readonly stale: boolean;
40		readonly exitCode: number | null;
41		readonly stderr: string;
42	
43		constructor(outcome: SessionOutcome) {
44			const detail = outcome.stderr.trim().split("\n").at(-1) ?? "";
45			super(
46				outcome.stale
47					? `stale session: ${detail}`
48					: `claude exited (code ${outcome.exitCode}, signal ${outcome.signal}) before system/init: ${detail}`,
49			);
50			this.name = "SessionSpawnError";
51			this.stale = outcome.stale;
52			this.exitCode = outcome.exitCode;
53			this.stderr = outcome.stderr;
54		}
55	}
56	
57	const STALE_STDERR = "No conversation found with session ID";
58	
59	// ANTHROPIC_API_KEY / ANTHROPIC_AUTH_TOKEN outrank subscription auth, and the
60	// nested-session markers make the child CLI believe it runs inside another
61	// Claude Code session; CLAUDE_CODE_OAUTH_TOKEN must survive for headless
62	// hosts.
63	const STRIPPED_ENV = new Set([
64		"ANTHROPIC_API_KEY",
65		"ANTHROPIC_AUTH_TOKEN",
66		"CLAUDECODE",
67		"CLAUDE_CODE_ENTRYPOINT",
68	]);
69	
70	function sessionEnv(): Record<string, string> {
71		const env: Record<string, string> = {};
72		for (const [key, value] of Object.entries(process.env)) {
73			if (value === undefined || STRIPPED_ENV.has(key)) continue;
74			env[key] = value;
75		}
76		return env;
77	}
78	
79	export function spawnSessionProcess(
80		options: SpawnSessionOptions,
81	): SessionProcess {
82		const row = spawnableRow(options.kind);
83		const args = [
84			"-p",
85			options.prompt,
86			// stream-json requires --verbose under -p.
87			"--output-format",
88			"stream-json",
89			"--verbose",
90			"--include-partial-messages",
91			"--model",
92			row.model,
93			"--effort",
94			row.effort,
95			// Explicit: the user's own config may default to a laxer mode (`auto`),
96			// which would execute tools outside the kind's allowlist.
97			"--permission-mode",
98			"default",
99			"--allowedTools",
100			row.tools.join(","),
101			"--append-system-prompt",
102			row.systemPrompt,
103			// Without it the user's global MCP servers load into every session.
104			"--strict-mcp-config",
105		];
106		if (options.resume !== undefined) args.push("--resume", options.resume);
107	
108		const child = spawn("claude", args, {
109			cwd: options.cwd,
110			env: sessionEnv(),
111			stdio: ["ignore", "pipe", "pipe"],
112		});
113	
114		let stderr = "";
115		child.stderr.on("data", (chunk: Buffer) => {
116			stderr += chunk.toString();
117		});
118	
119		let init: SessionInit | undefined;
120		const {
121			promise: started,
122			resolve: resolveStarted,
123			reject: rejectStarted,
124		} = Promise.withResolvers<SessionInit>();
125		// A caller may only await `done` (e.g. after kill); the rejection must not
126		// escape as an unhandled one.
127		started.catch(() => {});
128	
129		const lines = createInterface({ input: child.stdout });
130		lines.on("line", (line) => {
131			if (line.trim() === "") return;
132			let parsed: unknown;
133			try {
134				parsed = JSON.parse(line);
135			} catch {
136				return;
137			}
138			const event = sessionEventSchema.safeParse(parsed);
139			if (!event.success) return;
140			if (init === undefined) {
141				init = parseInitEvent(event.data);
142				if (init !== undefined) resolveStarted(init);
143			}
144			options.onEvent?.(event.data);
145		});
146	
147		const done = (async (): Promise<SessionOutcome> => {
148			const [exitCode, signal] = (await once(child, "close")) as [
149				number | null,
150				NodeJS.Signals | null,
151			];
152			const outcome: SessionOutcome = {
153				sessionId: init?.sessionId,
154				exitCode,
155				signal,
156				stale: exitCode === 1 && stderr.includes(STALE_STDERR),
157				stderr,
158			};
159			if (init === undefined) rejectStarted(new SessionSpawnError(outcome));
160			return outcome;
161		})();
162	
163		return {
164			started,
165			done,
166			kill: () => {
167				child.kill("SIGTERM");
168			},
169		};
170	}
171

