128		resume?: string;
129		attach?: Attach;
130	}
131	
132	async function runTurn(options: TurnOptions): Promise<{ sessionId: string }> {
133		const runId = randomUUID();
134		const { kind, attach } = options;
135		let sessionId = options.resume;
136		let resultSeen = false;
137		const child = spawnSessionProcess({
