152				// crash); the next resume must state that (steeringPrompt).
153				if (resultSeen || outcome.stale) interrupted.delete(sessionId);
154				else interrupted.add(sessionId);
155			}
156			handle?.broadcast("closed", {
157				runId,
158				kind,
159				sessionId,
160				exitCode: outcome.exitCode,
161				signal: outcome.signal,
162				stale: outcome.stale,
163			});
164		});
165		const init = await child.started;
166		live.set(init.sessionId, child);
