123	// A reason a snapshot cannot carry: shown as a toast. `illegal-transition` is
124	// an illegal hand edit the watcher accepted (files are the truth) but flags;
125	// `watch-error` is a filesystem/watcher failure.
126	export const noticeSchema = z.object({
127		kind: z.enum(["illegal-transition", "watch-error"]),
128		message: z.string(),
