1	import type { Dirent } from "node:fs";
2	import { mkdir, readdir, readFile, writeFile } from "node:fs/promises";
3	import { basename, dirname, join, relative, sep } from "node:path";
4	import { z } from "@fcalell/plugin-api/schema";
5	import { parse as parseYaml } from "yaml";
6	import {
7		parseBrief,
8		serializeEpic,
9		serializeStory,
10		splitFrontmatter,
11	} from "./markdown.ts";
12	import {
13		type Board,
14		type Epic,
15		type EpicFrontmatter,
16		epicFrontmatterSchema,
17		type InvalidFile,
18		type Story,
19		type StoryFrontmatter,
20		storyFrontmatterSchema,
21	} from "./schema.ts";
22	
23	export const EPIC_DIR_RE = /^(\d{3})-([a-z0-9-]+)$/;
24	export const STORY_FILE_RE = /^(\d{2})-([a-z0-9-]+)\.md$/;
25	
26	// One home for every classification message, so the loader and the watcher
27	// (both consumers of `classify`) cannot drift on wording.
28	export const INVALID_MESSAGES = {
29		fileInEpicsRoot: "unexpected file: boards contain only epic directories",
30		epicDirName: "epic directories are named <NNN>-<slug>",
31		storyFileName: "story files are named <NN>-<slug>.md",
32	} as const;
33	
34	export function duplicateEpicMessage(epicId: string): string {
35		return `duplicate epic number ${epicId}`;
36	}
37	
38	export function duplicateStoryMessage(storyId: string): string {
39		const [epicId, ordinal] = storyId.split("-");
40		return `duplicate story number ${ordinal} in epic ${epicId}`;
41	}
42	
43	export type { Board, Epic, InvalidFile, Story } from "./schema.ts";
44	
45	export class InvalidBoardFileError extends Error {
46		readonly path: string;
47	
48		constructor(path: string, message: string) {
49			super(message);
50			this.name = "InvalidBoardFileError";
51			this.path = path;
52		}
53	}
54	
55	export function isENOENT(error: unknown): boolean {
56		return (error as NodeJS.ErrnoException)?.code === "ENOENT";
57	}
58	
59	export function invalidFrom(path: string, error: unknown): InvalidFile {
60		if (error instanceof InvalidBoardFileError) {
61			return { path, message: error.message };
62		}
63		return {
64			path,
65			message: error instanceof Error ? error.message : String(error),
66		};
67	}
68	
69	// What a single path under `.helm/board/epics/` is. `kind` is the filesystem
70	// entry kind because the path alone cannot distinguish a directory named
71	// `01-foo.md/` from a story file. F4's duplicate-ordinal check sits in the
72	// scan layer above this (`scanBoard`, the watcher), which sees every path.
73	export type PathClass =
74		| { type: "epicDir"; epicId: string }
75		| { type: "epic"; epicId: string }
76		| { type: "story"; epicId: string }
77		| { type: "invalid"; message: string }
78		| { type: "ignored" };
79	
80	export function classify(
81		epicsDir: string,
82		path: string,
83		kind: "file" | "dir",
84	): PathClass {
85		const rel = relative(epicsDir, path);
86		if (rel === "" || rel.startsWith("..")) return { type: "ignored" };
87		const parts = rel.split(sep);
88		const dirName = parts[0];
89		if (dirName === undefined || dirName.startsWith(".")) {
90			return { type: "ignored" };
91		}
92	
93		if (parts.length === 1) {
94			if (kind === "file") {
95				return { type: "invalid", message: INVALID_MESSAGES.fileInEpicsRoot };
96			}
97			const epicId = EPIC_DIR_RE.exec(dirName)?.[1];
98			return epicId !== undefined
99				? { type: "epicDir", epicId }
100				: { type: "invalid", message: INVALID_MESSAGES.epicDirName };
101		}
102	
103		const entryName = parts[1];
104		if (parts.length === 2 && entryName !== undefined) {
105			if (entryName.startsWith(".")) return { type: "ignored" };
106			const epicId = EPIC_DIR_RE.exec(dirName)?.[1];
107			// The parent epic directory is itself invalid; it carries the banner.
108			if (epicId === undefined) return { type: "ignored" };
109			if (kind === "dir") {
110				return { type: "invalid", message: INVALID_MESSAGES.storyFileName };
111			}
112			if (entryName === "epic.md") return { type: "epic", epicId };
113			if (STORY_FILE_RE.test(entryName)) return { type: "story", epicId };
114			return { type: "invalid", message: INVALID_MESSAGES.storyFileName };
115		}
116	
117		// Deeper than a story file: below a directory already flagged at depth 2.
118		return { type: "ignored" };
119	}
120	
121	// A path index keyed by parsed id, `id -> paths`. Duplicate ids (`> 1` holder)
122	// are the collision the scan layer must fail loud on.
123	export type IdIndex = Map<string, Set<string>>;
124	
125	export function addToIndex(index: IdIndex, id: string, path: string): void {
126		const set = index.get(id);
127		if (set === undefined) index.set(id, new Set([path]));
128		else set.add(path);
129	}
130	
131	export function removeFromIndex(
132		index: IdIndex,
133		id: string,
134		path: string,
135	): void {
136		const set = index.get(id);
137		if (set === undefined) return;
138		set.delete(path);
139		if (set.size === 0) index.delete(id);
140	}
141	
142	export function storyOrdinal(path: string): string | undefined {
143		return STORY_FILE_RE.exec(basename(path))?.[1];
144	}
145	
146	function parseFrontmatter<S extends z.ZodType>(
147		path: string,
148		raw: string,
149		schema: S,
150	): { value: z.output<S>; body: string } {
151		const split = splitFrontmatter(raw);
152		if (split === undefined) {
153			throw new InvalidBoardFileError(path, "missing frontmatter fence");
154		}
155		let data: unknown;
156		try {
157			data = parseYaml(split.head);
158		} catch (error) {
159			const detail = error instanceof Error ? error.message : String(error);
160			throw new InvalidBoardFileError(
161				path,
162				`frontmatter is not valid YAML: ${detail}`,
163			);
164		}
165		const result = schema.safeParse(data);
166		if (!result.success) {
167			throw new InvalidBoardFileError(path, z.prettifyError(result.error));
168		}
169		return { value: result.data, body: split.body };
170	}
171	
172	export async function readStoryFile(
173		path: string,
174		epicId: string,
175	): Promise<Story> {
176		const raw = await readFile(path, "utf8");
177		const ordinal = storyOrdinal(path);
178		if (ordinal === undefined) {
179			throw new InvalidBoardFileError(path, INVALID_MESSAGES.storyFileName);
180		}
181		const { value, body } = parseFrontmatter(path, raw, storyFrontmatterSchema);
182		const expectedId = `${epicId}-${ordinal}`;
183		if (value.id !== expectedId) {
184			throw new InvalidBoardFileError(
185				path,
186				`frontmatter id ${value.id} does not match path-derived id ${expectedId}`,
187			);
188		}
189		return {
190			id: value.id,
191			epicId,
192			path,
193			frontmatter: value,
194			brief: parseBrief(body),
195			body,
196			raw,
197		};
198	}
199	
200	export async function readEpicFile(path: string): Promise<Epic> {
201		const raw = await readFile(path, "utf8");
202		const dirMatch = EPIC_DIR_RE.exec(basename(dirname(path)));
203		const id = dirMatch?.[1];
204		const slug = dirMatch?.[2];
205		if (id === undefined || slug === undefined) {
206			throw new InvalidBoardFileError(path, INVALID_MESSAGES.epicDirName);
207		}
208		const { value, body } = parseFrontmatter(path, raw, epicFrontmatterSchema);
209		return {
210			id,
211			slug,
212			path,
213			frontmatter: value,
214			title: parseBrief(body).title,
215			body,
216			raw,
217		};
218	}
219	
220	export function boardDir(repoPath: string): string {
221		return join(repoPath, ".helm", "board", "epics");
222	}
223	
224	export function epicFilePath(epicDir: string): string {
225		return join(epicDir, "epic.md");
226	}
227	
228	export async function ensureBoard(repoPath: string): Promise<void> {
229		await mkdir(boardDir(repoPath), { recursive: true });
230	}
231	
232	function sortedByName(entries: Dirent[]): Dirent[] {
233		return [...entries].sort((a, b) => a.name.localeCompare(b.name));
234	}
235	
236	function byPath<T extends { path: string }>(a: T, b: T): number {
237		return a.path.localeCompare(b.path);
238	}
239	
240	// The live shape both the loader and the watcher build: entities keyed by
241	// path plus the id indexes the duplicate-ordinal rule needs. `loadBoard`
242	// flattens it; the watcher seeds its own maps from it.
243	export interface ScanResult {
244		epics: Map<string, Epic>;
245		stories: Map<string, Story>;
246		invalid: Map<string, string>;
247		epicDirIds: IdIndex;
248		storyIds: IdIndex;
249	}
250	
251	async function scanEpicDir(
252		epicsDir: string,
253		dirPath: string,
254		epicId: string,
255		scan: ScanResult,
256	): Promise<void> {
257		const entries = await readdir(dirPath, { withFileTypes: true });
258		for (const entry of sortedByName(entries)) {
259			const path = join(dirPath, entry.name);
260			const kind = entry.isDirectory() ? "dir" : "file";
261			const c = classify(epicsDir, path, kind);
262			if (c.type === "ignored") continue;
263			if (c.type === "invalid") {
264				scan.invalid.set(path, c.message);
265				continue;
266			}
267			if (c.type === "epic") {
268				try {
269					scan.epics.set(path, await readEpicFile(path));
270				} catch (error) {
271					if (isENOENT(error)) continue;
272					scan.invalid.set(path, invalidFrom(path, error).message);
273				}
274			} else if (c.type === "story") {
275				const ordinal = storyOrdinal(path);
276				if (ordinal !== undefined) {
277					addToIndex(scan.storyIds, `${epicId}-${ordinal}`, path);
278				}
279				try {
280					scan.stories.set(path, await readStoryFile(path, epicId));
281				} catch (error) {
282					if (isENOENT(error)) continue;
283					scan.invalid.set(path, invalidFrom(path, error).message);
284				}
285			}
286		}
287	}
288	
289	function resolveCollisions(scan: ScanResult): void {
290		for (const [epicId, dirs] of scan.epicDirIds) {
291			if (dirs.size <= 1) continue;
292			for (const dir of dirs) {
293				scan.epics.delete(epicFilePath(dir));
294				scan.invalid.set(dir, duplicateEpicMessage(epicId));
295			}
296		}
297		for (const [storyId, paths] of scan.storyIds) {
298			if (paths.size <= 1) continue;
299			for (const path of paths) {
300				scan.stories.delete(path);
301				scan.invalid.set(path, duplicateStoryMessage(storyId));
302			}
303		}
304	}
305	
306	export async function scanBoard(repoPath: string): Promise<ScanResult> {
307		const scan: ScanResult = {
308			epics: new Map(),
309			stories: new Map(),
310			invalid: new Map(),
311			epicDirIds: new Map(),
312			storyIds: new Map(),
313		};
314		const epicsDir = boardDir(repoPath);
315		let entries: Dirent[];
316		try {
317			entries = await readdir(epicsDir, { withFileTypes: true });
318		} catch (error) {
319			if (isENOENT(error)) return scan;
320			throw error;
321		}
322		for (const entry of sortedByName(entries)) {
323			const path = join(epicsDir, entry.name);
324			const c = classify(epicsDir, path, entry.isDirectory() ? "dir" : "file");
325			if (c.type === "ignored") continue;
326			if (c.type === "invalid") {
327				scan.invalid.set(path, c.message);
328				continue;
329			}
330			if (c.type === "epicDir") {
331				addToIndex(scan.epicDirIds, c.epicId, path);
332				await scanEpicDir(epicsDir, path, c.epicId, scan);
333			}
334		}
335		resolveCollisions(scan);
336		return scan;
337	}
338	
339	export async function loadBoard(repoPath: string): Promise<Board> {
340		const scan = await scanBoard(repoPath);
341		return {
342			epics: [...scan.epics.values()].sort(byPath),
343			stories: [...scan.stories.values()].sort(byPath),
344			invalid: [...scan.invalid.entries()]
345				.map(([path, message]) => ({ path, message }))
346				.sort(byPath),
347		};
348	}
349	
350	export async function writeStory(
351		story: Pick<Story, "path" | "frontmatter" | "body">,
352	): Promise<void> {
353		await writeFile(
354			story.path,
355			serializeStory(story.frontmatter, story.body),
356			"utf8",
357		);
358	}
359	
360	export async function writeEpic(
361		epic: Pick<Epic, "path" | "frontmatter" | "body">,
362	): Promise<void> {
363		await writeFile(
364			epic.path,
365			serializeEpic(epic.frontmatter, epic.body),
366			"utf8",
367		);
368	}
369	
370	// Session ids attach through a fresh read-modify-write so a hand edit made
371	// since the last snapshot survives; callers serialize through the write
372	// queue like every other board write.
373	export async function attachStorySession(
374		path: string,
375		epicId: string,
376		kind: keyof StoryFrontmatter["sessions"],
377		sessionId: string,
378	): Promise<void> {
379		const story = await readStoryFile(path, epicId);
380		await writeStory({
381			path,
382			frontmatter: {
383				...story.frontmatter,
384				sessions: { ...story.frontmatter.sessions, [kind]: sessionId },
385			},
386			body: story.body,
387		});
388	}
389	
390	export async function attachEpicSession(
391		path: string,
392		kind: keyof EpicFrontmatter["sessions"],
393		sessionId: string,
394	): Promise<void> {
395		const epic = await readEpicFile(path);
396		await writeEpic({
397			path,
398			frontmatter: {
399				...epic.frontmatter,
400				sessions: { ...epic.frontmatter.sessions, [kind]: sessionId },
401			},
402			body: epic.body,
403		});
404	}
405

