7	import { runClaude, setupToyRepo, summarize, TOY_REPO } from "./lib.ts";
8	
9	setupToyRepo();
10	
11	const received: unknown[] = [];
12	
13	// Stateless transport: the SDK allows one transport per server instance, so
14	// build a fresh McpServer per request.
15	function buildMcpServer(): McpServer {
16		const mcp = new McpServer({ name: "helm", version: "0.0.0" });
17		mcp.registerTool(
18			"update_card",
19			{
20				description:
21					"Record a note on the story card. Use this to log decisions.",
22				inputSchema: { note: z.string().describe("The note to record") },
23			},
24			async ({ note }) => {
25				received.push(note);
26				console.log(`  [server] update_card called: ${note}`);
27				return { content: [{ type: "text", text: "recorded" }] };
28			},
29		);
30		return mcp;
31	}
32	
33	const httpServer = createServer(async (req, res) => {
34		const transport = new StreamableHTTPServerTransport({
35			sessionIdGenerator: undefined,
36		});
37		await buildMcpServer().connect(transport);
38		await transport.handleRequest(req, res);
39	});
40	await new Promise<void>((resolve) =>
41		httpServer.listen(0, "127.0.0.1", resolve),
42	);
43	const address = httpServer.address();
44	if (address === null || typeof address === "string")
45		throw new Error("no port");
46	const url = `http://127.0.0.1:${address.port}/mcp`;
47	console.log(`MCP server on ${url}`);
48	
49	const mcpConfig = JSON.stringify({
50		mcpServers: { helm: { type: "http", url } },
51	});
52	
53	const run = await runClaude({
54		cwd: TOY_REPO,
55		prompt:
56			"Call the update_card tool exactly once with the note " +
57			"'spike says hello', then reply 'done'.",
58		args: [
