input.new_string:
export interface ToolDefinition {
	description: string;
	// The tool's input schema. Passed to the SDK as an object schema (not a raw
	// shape): SDK 1.29's `registerTool` types the raw-shape overload against a
	// zod-core `$ZodType` our zod re-export does not satisfy, and the object form
	// validates identically while handing the callback `args: unknown`.
	inputSchema(kind: SessionKind): z.ZodObject;
	handle(binding: SpawnBinding, args: unknown): Promise<CallToolResult>;
}

