8	export function buildMcpServer(binding: SpawnBinding): McpServer {
9		const mcp = new McpServer({ name: MCP_SERVER_NAME, version: "0.0.0" });
10		for (const name of KIND_REGISTRY[binding.kind].boardTools ?? []) {
11			const def = TOOL_TABLE[name];
12			mcp.registerTool(
13				name,
14				{ description: def.description, inputSchema: def.inputSchema(binding.kind) },
15				(args) => def.handle(binding, args),
16			);
17		}
18		return mcp;
19	}

