119	export async function resolveProposalItem(input: {
120		proposalId: string;
121		item: number;
122		resolution: ProposalResolution;
123	}): Promise<void> {
124		const proposal = proposals.get(input.proposalId);
125		const item = proposal?.items[input.item];
126		if (proposal === undefined || item === undefined) {
127			throw new ApiError("NOT_FOUND", {
128				message: `no proposal item ${input.proposalId}[${input.item}]`,
129			});
130		}
131		if (item.resolution !== undefined) {
132			throw new ApiError("PROPOSAL_RESOLVED", {
133				status: 409,
134				message: "this item is already resolved",
135			});
136		}
137		const { resolution } = input;
138		if (
139			proposal.tool === "flag_risk" ||
140			(proposal.tool === "raise_decision" && resolution.type === "accept")
141		) {
142			throw new ApiError("UNSUPPORTED_RESOLUTION", {
143				status: 501,
144				message: `${proposal.tool} resolution is not implemented yet`,
145			});
146		}
147		if (resolution.type === "edit") {
148			const parsed = ITEM_SCHEMA[proposal.tool].safeParse(resolution.payload);
149			if (!parsed.success) {
150				throw new ApiError("BAD_REQUEST", {
151					message: z.prettifyError(parsed.error),
152				});
153			}
154			// The store owns this object and the payload was just re-validated against
155			// the tool's item schema; the union widens `payload` to `never` here.
156			(item as { payload: unknown }).payload = parsed.data;
157		}
158		if (resolution.type === "accept" || resolution.type === "edit") {
159			await enqueueWrite(() => applyItem(proposal, input.item));
160		}
161		item.resolution = resolution;
162		broadcast();
163		if (proposal.items.every((each) => each.resolution !== undefined)) {
164			proposals.delete(proposal.id);
165			contexts.delete(proposal.id);
166			broadcast();
167			const changed = proposal.items.some(
168				(each) =>
169					each.resolution?.type === "edit" || each.resolution?.type === "reject",
170			);
171			if (changed)
172				await dispatchResume(proposal.sessionId, composeOutcome(proposal));
173		}
