import WebSocket from "/home/fcalell/projects/helm-wt-001-02/node_modules/ws/index.js";

const BASE = "http://localhost:8788";
async function rpc(path, input) {
  const res = await fetch(`${BASE}/rpc/${path}`, {
    method: "POST", headers: { "content-type": "application/json" },
    body: JSON.stringify({ json: input }),
  });
  const text = await res.text();
  try { return { status: res.status, body: JSON.parse(text) }; }
  catch { return { status: res.status, body: text }; }
}

const inits = [], proposalSnaps = [], boardSnaps = [], assistantTexts = [], closed = [];
const ws = new WebSocket(`ws://localhost:8788/ws`);
await new Promise((r, j) => { ws.on("open", r); ws.on("error", j); });
for (const ch of ["session", "proposal", "board"]) ws.send(JSON.stringify({ t: "sub", ch }));
ws.on("message", (raw) => {
  const f = JSON.parse(raw.toString());
  if (f.ch === "session" && f.type === "event") {
    const e = f.payload.event;
    if (e.type === "system" && e.subtype === "init") inits.push(e);
    if (e.type === "assistant" && e.message?.content) {
      for (const c of e.message.content) if (c.type === "text") assistantTexts.push(c.text);
    }
  }
  if (f.ch === "session" && f.type === "closed") closed.push(f.payload);
  if (f.ch === "proposal" && f.type === "snapshot") proposalSnaps.push(f.payload);
  if (f.ch === "board" && f.type === "snapshot") boardSnaps.push(f.payload);
});

const cmd = process.argv[2];
const arg = process.argv[3];

if (cmd === "spawn") {
  const prompt = arg;
  const out = await rpc("session/spawn", { kind: "shape", prompt });
  console.log("SPAWN status", out.status, JSON.stringify(out.body).slice(0, 300));
  // wait for closed or timeout
  const t0 = Date.now();
  while (closed.length === 0 && Date.now() - t0 < 120000) await new Promise(r => setTimeout(r, 500));
  await new Promise(r => setTimeout(r, 800)); // drain trailing frames
  const init = inits[0];
  console.log("=== system/init ===");
  console.log("mcp_servers:", JSON.stringify(init?.mcp_servers));
  console.log("tools (mcp only):", JSON.stringify((init?.tools||[]).filter(t=>t.startsWith("mcp__"))));
  console.log("tools (all):", JSON.stringify(init?.tools));
  console.log("=== proposal snapshots:", proposalSnaps.length);
  const last = proposalSnaps.at(-1);
  console.log("last proposal snapshot:", JSON.stringify(last, null, 1)?.slice(0, 1500));
  console.log("=== board snapshots:", boardSnaps.length, "last epics:", JSON.stringify(boardSnaps.at(-1)?.epics?.map(e=>e.id)));
  console.log("=== assistant texts:", JSON.stringify(assistantTexts).slice(0,500));
  console.log("=== closed:", JSON.stringify(closed));
  // stash the pending proposal id for follow-up
  const pending = last?.proposals?.[0];
  if (pending) console.log("PENDING_PROPOSAL_ID=" + pending.id + " ITEMS=" + pending.items.length);
  const q = last?.questions?.[0];
  if (q) console.log("PENDING_QUESTION_ID=" + q.id);
}
ws.close();
process.exit(0);
EOF
