			if (matches.length === 0) {
				return err(`no epic with slug ${parsed.data.epic}`);
			}
			if (matches.length > 1) {
				return err(`epic slug ${parsed.data.epic} is ambiguous`);
			}
			return recordedProposal(
				recordProposal(
					ready,
					"propose_stories",
					parsed.data.stories,
